package jetbrains.mps.java.workbench.actions;

/*Generated by MPS */

import jetbrains.mps.workbench.action.BaseAction;
import javax.swing.Icon;
import org.jetbrains.annotations.NotNull;
import com.intellij.openapi.actionSystem.AnActionEvent;
import java.util.Map;
import jetbrains.mps.openapi.editor.message.SimpleEditorMessage;
import jetbrains.mps.ide.editor.MPSEditorDataKeys;
import jetbrains.mps.java.platform.highlighters.CommentSpellChecker;
import jetbrains.mps.project.MPSProject;
import jetbrains.mps.ide.actions.MPSCommonDataKeys;
import jetbrains.mps.openapi.editor.cells.EditorCell;

public class AddWordToDictionary_Action extends BaseAction {
  private static final Icon ICON = null;

  public AddWordToDictionary_Action() {
    super("Add Word to Dictionary", "", ICON);
    this.setIsAlwaysVisible(false);
    this.setExecuteOutsideCommand(false);
  }
  @Override
  public boolean isDumbAware() {
    return true;
  }
  @Override
  public void doUpdate(@NotNull AnActionEvent event, final Map<String, Object> _params) {
    // To contribute the action to editor menu, I use EditorPopup which is defined in plugin.xml 
    // Therefore, all contributions have to be declared in plugin.xml as well (at least in j.m.java.workbench 
    // as it doesn't use plugin.standalone). However, contributions through plugin.xml can not be dynamic, 
    // and I'm limited to a static contribution of a single action. Therefore, I show action for the first mistake only. 
    for (SimpleEditorMessage msg : event.getData(MPSEditorDataKeys.EDITOR_CELL).getMessages()) {
      if (!(CommentSpellChecker.isSpellcheckerMessage(msg))) {
        continue;
      }
      String[] incorrectWords = CommentSpellChecker.incorrectWords(msg);
      if (incorrectWords == null || incorrectWords.length == 0) {
        continue;
      }
      String firstWord = incorrectWords[0];
      event.getPresentation().setText(String.format("Add '%s' to dictionary", firstWord));
      event.getPresentation().setEnabledAndVisible(true);
      event.getPresentation().putClientProperty("AddWordToDictionary", firstWord);
      return;
    }
    event.getPresentation().setEnabledAndVisible(false);
  }
  @Override
  protected boolean collectActionData(AnActionEvent event, final Map<String, Object> _params) {
    if (!(super.collectActionData(event, _params))) {
      return false;
    }
    {
      MPSProject p = event.getData(MPSCommonDataKeys.MPS_PROJECT);
      if (p == null) {
        return false;
      }
    }
    {
      EditorCell p = event.getData(MPSEditorDataKeys.EDITOR_CELL);
      if (p == null) {
        return false;
      }
    }
    return true;
  }
  @Override
  public void doExecute(@NotNull final AnActionEvent event, final Map<String, Object> _params) {
    Object word = event.getPresentation().getClientProperty("AddWordToDictionary");
    if (word == null) {
      return;
    }
    CommentSpellChecker.addToDictionary(event.getData(MPSCommonDataKeys.MPS_PROJECT).getProject(), String.valueOf(word));
  }
}
